&lt;pre&gt;   // Returns “ClassName{}&lt;/pre&gt;&lt;br&gt;
   {@code
     // Returns “ClassName{x=1}”
     MoreObjects.toStringHelper(this)
         .toString();

     // Returns “MyObject{x=1}”
     MoreObjects.toStringHelper("MyObject")
         .add("x", 1)
         .toString();&lt;/code&gt;&lt;br&gt;
   MoreObjects.toStringHelper(this)
         .add("x", 1)
         .toString();&lt;/pre&gt;&lt;br&gt;
   // Returns “ClassName{x=1, y=foo}”
   MoreObjects.toStringHelper(this)
         .add("x", 1)
         .add("y", "foo")
         .toString();&lt;/code&gt;&lt;br&gt;
   // Returns “ClassName{x=1}”
   MoreObjects.toStringHelper(this)
         .omitNullValues()
         .add("x", 1)
         .add("y", null)
         .toString();&lt;/code&gt;&lt;br&gt;
   // Note that in GWT, class names are often obfuscated.&lt;/pre&gt;
